[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/var/temperature> ;
            sh:resultMessage "For data description level, a cdi:InstanceVariable should specify cdi:physicalDataType." ;
            sh:resultPath cdi:physicalDataType ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "For data description level, a cdi:InstanceVariable should specify cdi:physicalDataType." ;
                    sh:minCount 1 ;
                    sh:or ( [ sh:nodeKind sh:IRI ] [ sh:datatype xsd:string ;
                                sh:minLength 3 ] [ sh:class schema1:DefinedTerm ] ) ;
                    sh:path cdi:physicalDataType ;
                    sh:severity sh:Warning ] ] .

